//#region src/features/resolvers/composables/useDynamicCredentials.ts
/**
* Gates the external/custom credential resolver surfaces (resolver management
* page, workflow-level resolver dropdown, custom resolver create/edit). This is
* the superset capability.
*
* For the base "private credentials" surfaces (per-user self-connect via the
* system resolver) use `usePrivateCredentials`.
*/
var useDynamicCredentials = () => {
	const settingsStore = useSettingsStore();
	const { check } = useEnvFeatureFlag();
	return { isEnabled: computed(() => settingsStore.isModuleActive("dynamic-credentials") && check.value("DYNAMIC_CREDENTIALS")) };
};
//#endregion
//#region src/features/ai/instanceAi/instanceAiPermissions.ts
/** Sending messages to Instance AI (and reaching the chat view) requires this scope. */
function canMessageInstanceAi() {
	return hasPermission(["rbac"], { rbac: { scope: "instanceAi:message" } });
}
